SELECT orders.customer_id, customers.id
FROM orders CROSS JOIN customers
WHERE (orders.id IS NOT NULL AND (orders.customer_id <= 190 AND customers.region_id IN (1, 5, 8, 9)));

SELECT t0.id
FROM employees AS t0
WHERE t0.department_id NOT IN (6, 11, 32, 94);

SELECT markets.region, markets.id, markets.note
FROM markets
WHERE markets.region IS NULL;

SELECT t0.id, t0.region_id, SUM(t0.region_id)
FROM customers AS t0
GROUP BY t0.id, t0.region_id;

SELECT regions.id, customers.id, customers.region_id
FROM regions JOIN customers ON regions.id = customers.id
WHERE (customers.id NOT BETWEEN 18 AND 150 OR regions.id IN (1, 9, 10, 63));
